using System;
using System.Runtime.InteropServices;
using System.Text;

public class AudioDefaults {
  public enum EDataFlow { eRender, eCapture, eAll }
  public enum ERole { eConsole, eMultimedia, eCommunications }
  [ComImport, Guid("BCDE0395-E52F-467C-8E3D-C4579291692E")] class MMDeviceEnumerator {}
  [Guid("A95664D2-9614-4F35-A746-DE8DB63617E6"), InterfaceType(ComInterfaceType.InterfaceIsIUnknown)]
  interface IMMDeviceEnumerator { int NotImpl1(); int GetDefaultAudioEndpoint(EDataFlow dataFlow, ERole role, out IMMDevice ppDevice); }
  [Guid("D666063F-1587-4E43-81F1-B948E807363F"), InterfaceType(ComInterfaceType.InterfaceIsIUnknown)]
  interface IMMDevice { int Activate(ref Guid iid, int dwClsCtx, IntPtr pActivationParams, out IntPtr ppInterface); int OpenPropertyStore(int stgmAccess, out IPropertyStore ppProperties); int GetId([MarshalAs(UnmanagedType.LPWStr)] out string ppstrId); int GetState(out int pdwState); }
  [Guid("886d8eeb-8cf2-4446-8d02-cdba1dbdcf99"), InterfaceType(ComInterfaceType.InterfaceIsIUnknown)]
  interface IPropertyStore { int GetCount(out int cProps); int GetAt(int iProp, out PROPERTYKEY pkey); int GetValue(ref PROPERTYKEY key, out PROPVARIANT pv); int SetValue(ref PROPERTYKEY key, ref PROPVARIANT pv); int Commit(); }
  [StructLayout(LayoutKind.Sequential)] struct PROPERTYKEY { public Guid fmtid; public int pid; }
  [StructLayout(LayoutKind.Sequential)] struct PROPVARIANT { public ushort vt; ushort wReserved1, wReserved2, wReserved3; public IntPtr p; }
  public static string GetName(IMMDevice dev) { IPropertyStore store; dev.OpenPropertyStore(0, out store); var key = new PROPERTYKEY { fmtid = new Guid("a45c254e-df1c-4efd-8020-67d146a850e0"), pid = 14 }; PROPVARIANT pv; store.GetValue(ref key, out pv); return Marshal.PtrToStringUni(pv.p); }
  public static void Print() { var en = (IMMDeviceEnumerator)(new MMDeviceEnumerator()); foreach (EDataFlow flow in new []{EDataFlow.eRender,EDataFlow.eCapture}) foreach (ERole role in new []{ERole.eConsole,ERole.eMultimedia,ERole.eCommunications}) { IMMDevice d; int hr=en.GetDefaultAudioEndpoint(flow, role, out d); if (hr==0) { string id; d.GetId(out id); Console.WriteLine(flow+"/"+role+" => "+GetName(d)+" | "+id); } else Console.WriteLine(flow+"/"+role+" => <none> hr="+hr); } }
}
'@
Add-Type -TypeDefinition $code
[AudioDefaults]::Print()","workdir":"C:\Users\KSR\Documents\Codex\2026-06-04\new-chat","timeout_ms":10000}

